noncompliant:
[[deprecated]]  // Noncompliant - no explanation
void oldFunction();

__attribute__((deprecated))  // Noncompliant - no explanation
void anotherOldFunction();

__declspec(deprecated)  // Noncompliant - no explanation
void yetAnotherOldFunction();

compliant:
[[deprecated("Use newFunction() instead")]]  // Compliant
void oldFunction();

__attribute__((deprecated("This function is unsafe, use saferFunction() instead")))  // Compliant
void anotherOldFunction();

__declspec(deprecated("Will be removed in v2.0, migrate to modernFunction()"))  // Compliant
void yetAnotherOldFunction();
